+import sys
+import numpy as np
+
+alpha = json.loads(sys.argv[1])
+size = int(sys.argv[2])
+rng = np.random.Generator(np.random.PCG64DXSM(12345))
+out = rng.dirichlet(alpha, size=size)
+for row in out:
+    print(",".join(str(float(value)) for value in row.tolist()))
+"#;
+        let output = Command::new(oracle_python_bin())
+            .arg("-c")
